# Let's recursively generate downsets n small via monotone Boolean functions
def gen_downsets(n):
    if n==0:
        yield {0}; return
    # D = E union {sets with new bit and base in F}, F subset E downsets on n-1
    downs=list(gen_downsets(n-1))
    for E in downs:
        for F in downs:
            if F.issubset(E):
                D=set(E)|{A | (1<<(n-1)) for A in F}
                yield D

