def prob_tail(weights, p, thresh, ge=True):
    n=len(weights); val=0.0
    for mask in range(1<<n):
        total=sum(weights[i] for i in range(n) if mask>>i&1)
        k=mask.bit_count()
        if (total>=thresh-1e-12 if ge else total<thresh-1e-12):
            val+=p**k*(1-p)**(n-k)
    return val
