import math
def bin_tail(N,p,k):
    return sum(math.comb(N,j)*p**j*(1-p)**(N-j) for j in range(k,N+1))
def pivot_dust_tail(p,eps,N):
    c=(1-p+eps)/N
    # need bin >= ceil(threshold/c)
    k1=math.ceil((eps)/c -1e-12)
    k0=math.ceil((p)/c -1e-12)
    return p*bin_tail(N,p,k1)+(1-p)*bin_tail(N,p,k0)
